('additional-maths:8-3-stationary-points-and-curve-sketching:fib:c4211bcf', 'additional-maths', 'additional-maths:8-3-stationary-points-and-curve-sketching', '8.3 Stationary Points and Curve Sketching', 'fib', 'fib', 1, '{"question": "At a stationary point of inflection the gradient is zero but does ___B1___ change sign as you pass through.", "blankOptions": {"B1": ["maximum", "determine", "positive", "not"]}}'::jsonb, '{"blanks": {"B1": "not"}}'::jsonb),
('additional-maths:8-3-stationary-points-and-curve-sketching:fib:c103769e', 'additional-maths', 'additional-maths:8-3-stationary-points-and-curve-sketching', '8.3 Stationary Points and Curve Sketching', 'fib', 'fib', 2, '{"question": "To sketch a cubic you use its stationary points, its ___B1___ with the axes and its long-run ___B2___.", "blankOptions": {"B1": ["not", "either side", "intercepts", "gradient"], "B2": ["behaviour", "inconclusive", "negative", "determine"]}}'::jsonb, '{"blanks": {"B1": "intercepts", "B2": "behaviour"}}'::jsonb),
